// // This module implements a 4-bit synchronous counter with a parallel load option.
// It has three inputs: a clock input, a reset input, and a parallel load input.
// The module has a 4-bit output representing the current count.
// If the parallel load input is high, the counter should load the value of a 4-bit input (load_input) into the counter.
// If the parallel load input is low, the counter should decrement on every rising edge of the clock input.
// If the reset input is high, the counter should reset to zero.
module sync_counter_4bit (
  input clk,
  input reset,
  input parallel_load,
  input [3:0] load_input,
  output reg [3:0] count
);

  always @(posedge clk or posedge reset) begin
    if (reset) begin
      count <= 4'b0;
    end else if (parallel_load) begin
      count <= load_input;
    end else begin
      count <= count + 1;
    end
  end

endmodule

